+    }
+
+    /// Render to markdown
+    pub fn to_markdown(&self) -> String {
+        if self.patterns.is_empty() {
+            return String::new();
+        }
+
+        let mut output = format!("{}\n\n", self.header);
+        for pattern in &self.patterns {
