+            md.push_str(&format!("**Context:** {}\n\n", example.context));
+            md.push_str(&format!("```\n{}\n```\n\n", example.content));
+        }
+    }
+
+    if !draft.avoid_when.is_empty() {
+        md.push_str("## Avoid When\n\n");
+        for avoid in &draft.avoid_when {
+            md.push_str(&format!("- {}\n", avoid));
+        }
+        md.push_str("\n");
